SELECT user_id AS userId, SUM(amount) AS amount
FROM bill_daily_revenue
WHERE dt >= #{monthStart} AND dt <= #{monthEnd}

    AND user_id = #{userId}

GROUP BY user_id
ORDER BY amount DESC

SELECT COUNT(DISTINCT user_id)
FROM bill_daily_revenue
WHERE dt >= #{monthStart} AND dt <= #{monthEnd}

    AND user_id = #{userId}

LIMIT 20

SELECT dt, user_id, amount, status
FROM bill_daily_revenue
WHERE dt >= #{monthStart} AND dt <= #{monthEnd}

    AND user_id = #{userId}


    AND status = #{status}

ORDER BY dt DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM bill_daily_revenue
WHERE dt >= #{monthStart} AND dt <= #{monthEnd}

    AND user_id = #{userId}


    AND status = #{status}
